mapper.select:
select m.id, m.email, m.nickname, m.real_name, m.role, m.status, m.creator_verified, m.creator_tier, m.follower_count, m.created_datetime as created_at, case when m.creator_verified = true then '작가' else '컬렉터' end as member_type, ( select count(*) from tbl_report r where r.target_type = 'MEMBER' and r.target_id = m.id ) as report_count, ( select count(*) from tbl_order o where o.buyer_id = m.id or o.seller_id = m.id ) as transaction_count from tbl_member m
m.deleted_datetime is null
and ( m.email ilike '%' || #{keyword} || '%' or m.nickname ilike '%' || #{keyword} || '%' or m.real_name ilike '%' || #{keyword} || '%' )
and m.role = #{role}
and m.status = #{status}
and m.creator_verified = #{creatorVerified}
order by m.created_datetime desc limit #{size} offset #{offset}

select count(*)
from tbl_member m

    m.deleted_datetime is null

        and (
            m.email ilike '%' || #{keyword} || '%'
            or m.nickname ilike '%' || #{keyword} || '%'
            or m.real_name ilike '%' || #{keyword} || '%'
        )


        and m.role = #{role}


        and m.status = #{status}


        and m.creator_verified = #{creatorVerified}
